                     "Connection: close\r\n"
                     "Content-Type: %s\r\n"
                     "Content-Length: %zu\r\n"
                     "\r\n",
                     code, status, ctype, blen);
    if (n < 0) return;
    write_all(fd, hdr, (size_t)n);
    if (body) write_all(fd, body, blen);
}

static void send_file(int fd, const char *fs_path) {
