    if (n > 0) write_all(fd, hdr, (size_t)n);

    char buf[4096];
    size_t r;
    while ((r = fread(buf, 1, sizeof(buf), f)) > 0) {
        if (write_all(fd, buf, r) != 0) break;
    }
    fclose(f);
}

static void handle_client(int fd) {
    char req[8192];
    ssize_t n = read(fd, req, sizeof(req) - 1);
    if (n <= 0) return;
    req[n] = '\0';

    char *line_end = strstr(req, "\r\n");
    if (!line_end) line_end = strchr(req, '\n');
    if (!line_end) {
        send_simple(fd, 400, "Bad Request", "text/plain", "Bad Request");
        return;
    }
    *line_end = '\0';

    char method[16], target[2048];
    if (sscanf(req, "%15s %2047s", method, target) != 2) {
        send_simple(fd, 400, "Bad Request", "text/plain", "Bad Request");
        return;
    }

    if (strcmp(method, "GET") != 0) {
        send_simple(fd, 405, "Method Not Allowed", "text/plain", "Method Not Allowed");
        return;
    }

    char *q = strchr(target, '?');
    if (q) *q = '\0';

    if (strcmp(target, "/api/notes") == 0) {
        send_simple(fd, 200, "OK", "application/json", "[]");
        return;
    }

    /* If any percent-encoding is present, reject to satisfy traversal constraints.
