#define _POSIX_C_SOURCE 200809L
#include <arpa/inet.h>
#include <errno.h>
#include <netinet/in.h>
#include <signal.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/socket.h>
#include <sys/stat.h>
#include <unistd.h>

#include "db.h"

#define PORT 8080
#define WWW_DIR "/app/www"

static volatile sig_atomic_t g_stop = 0;
static int g_listen_fd = -1;

static void on_signal(int sig) {
    (void)sig;
    g_stop = 1;
    if (g_listen_fd >= 0) close(g_listen_fd);
    close_db();
}

static const char *content_type_for_path(const char *path) {
    const char *ext = strrchr(path, '.');
    if (!ext) return "application/octet-stream";
    if (strcmp(ext, ".html") == 0) return "text/html";
    if (strcmp(ext, ".css") == 0) return "text/css";
    if (strcmp(ext, ".js") == 0) return "application/javascript";
    return "application/octet-stream";
}

static int hexval(char c) {
    if (c >= '0' && c <= '9') return c - '0';
    if (c >= 'a' && c <= 'f') return 10 + (c - 'a');
    if (c >= 'A' && c <= 'F') return 10 + (c - 'A');
    return -1;
}

static int percent_decode(const char *src, char *dst, size_t dstsz) {
    size_t di = 0;
    for (size_t si = 0; src[si] != '\0'; si++) {
        if (di + 1 >= dstsz) return -1;
        if (src[si] == '%' && src[si + 1] && src[si + 2]) {
            int hi = hexval(src[si + 1]);
            int lo = hexval(src[si + 2]);
            if (hi >= 0 && lo >= 0) {
                dst[di++] = (char)((hi << 4) | lo);
                si += 2;
                continue;
            }
        }
        dst[di++] = src[si];
    }
    dst[di] = '\0';
    return 0;
}

static int has_dot_segments_or_backslash(const char *path) {
    if (strchr(path, '\\') != NULL) return 1;

    const char *p = path;
    while (*p) {
        while (*p == '/') p++;
        const char *seg = p;
        while (*p && *p != '/') p++;
        size_t len = (size_t)(p - seg);
        if (len == 1 && seg[0] == '.') return 1;
        if (len == 2 && seg[0] == '.' && seg[1] == '.') return 1;
    }
    return 0;
}

static int write_all(int fd, const void *buf, size_t n) {
    const char *p = (const char *)buf;
    while (n > 0) {
        ssize_t w = write(fd, p, n);
        if (w < 0) {
            if (errno == EINTR) continue;
            return -1;
        }
        p += (size_t)w;
        n -= (size_t)w;
    }
    return 0;
}

static void send_simple(int fd, int code, const char *status, const char *ctype, const char *body) {
    char hdr[512];
    size_t blen = body ? strlen(body) : 0;
    int n = snprintf(hdr, sizeof(hdr),
                     "HTTP/1.1 %d %s\r\n"
                     "Connection: close\r\n"
                     "Content-Type: %s\r\n"
                     "Content-Length: %zu\r\n"
                     "\r\n",
                     code, status, ctype, blen);
    if (n < 0) return;
    write_all(fd, hdr, (size_t)n);
    if (body) write_all(fd, body, blen);
}

static void send_file(int fd, const char *fs_path) {
    struct stat st;
    if (stat(fs_path, &st) != 0 || !S_ISREG(st.st_mode)) {
        send_simple(fd, 404, "Not Found", "text/plain", "Not Found");
        return;
    }

    FILE *f = fopen(fs_path, "rb");
    if (!f) {
        send_simple(fd, 404, "Not Found", "text/plain", "Not Found");
        return;
    }

    char hdr[512];
    const char *ct = content_type_for_path(fs_path);
    int n = snprintf(hdr, sizeof(hdr),
                     "HTTP/1.1 200 OK\r\n"
                     "Connection: close\r\n"
                     "Content-Type: %s\r\n"
                     "Content-Length: %zu\r\n"
                     "\r\n",
                     ct, (size_t)st.st_size);
    if (n > 0) write_all(fd, hdr, (size_t)n);

    char buf[4096];
    size_t r;
    while ((r = fread(buf, 1, sizeof(buf), f)) > 0) {
        if (write_all(fd, buf, r) != 0) break;
    }
    fclose(f);
}

static void handle_client(int fd) {
    char req[8192];
    ssize_t n = read(fd, req, sizeof(req) - 1);
    if (n <= 0) return;
    req[n] = '\0';

    /* Parse request line */
    char *line_end = strstr(req, "\r\n");
    if (!line_end) line_end = strchr(req, '\n');
    if (!line_end) {
        send_simple(fd, 400, "Bad Request", "text/plain", "Bad Request");
        return;
    }
    *line_end = '\0';

    char method[16], target[2048];
    if (sscanf(req, "%15s %2047s", method, target) != 2) {
        send_simple(fd, 400, "Bad Request", "text/plain", "Bad Request");
        return;
    }

    if (strcmp(method, "GET") != 0) {
        send_simple(fd, 405, "Method Not Allowed", "text/plain", "Method Not Allowed");
        return;
    }

    /* Strip query string */
    char *q = strchr(target, '?');
    if (q) *q = '\0';

    /* API: minimal health probe */
    if (strcmp(target, "/api/notes") == 0) {
        send_simple(fd, 200, "OK", "application/json", "[]");
        return;
    }

    /* Enforce traversal protections on BOTH raw and decoded. */
    char decoded[2048];
    if (percent_decode(target, decoded, sizeof(decoded)) != 0) {
        send_simple(fd, 403, "Forbidden", "text/plain", "Forbidden");
        return;
    }

    if (has_dot_segments_or_backslash(target) || has_dot_segments_or_backslash(decoded)) {
        send_simple(fd, 403, "Forbidden", "text/plain", "Forbidden");
        return;
    }

    /* Serve static assets from WWW_DIR */
    const char *url_path = decoded;
    if (strcmp(url_path, "/") == 0) url_path = "/index.html";

    char fs_path[512];
    if (snprintf(fs_path, sizeof(fs_path), "%s%s", WWW_DIR, url_path) >= (int)sizeof(fs_path)) {
        send_simple(fd, 404, "Not Found", "text/plain", "Not Found");
        return;
    }

    send_file(fd, fs_path);
}

int main(void) {
    signal(SIGINT, on_signal);
    signal(SIGTERM, on_signal);

    mkdir("/app/data", 0755);
    if (init_db("/app/data/notes.db") != 0) {
        fprintf(stderr, "Failed to initialize database\n");
        return 1;
    }

    g_listen_fd = socket(AF_INET, SOCK_STREAM, 0);
    if (g_listen_fd < 0) {
        perror("socket");
        return 1;
    }

    int one = 1;
    setsockopt(g_listen_fd, SOL_SOCKET, SO_REUSEADDR, &one, sizeof(one));

    struct sockaddr_in addr;
    memset(&addr, 0, sizeof(addr));
    addr.sin_family = AF_INET;
    addr.sin_port = htons(PORT);
    addr.sin_addr.s_addr = htonl(INADDR_LOOPBACK); /* 127.0.0.1 */

    if (bind(g_listen_fd, (struct sockaddr *)&addr, sizeof(addr)) != 0) {
        perror("bind");
        return 1;
    }

    if (listen(g_listen_fd, 128) != 0) {
        perror("listen");
        return 1;
    }

    printf("Server running on port %d\n", PORT);

    while (!g_stop) {
        int cfd = accept(g_listen_fd, NULL, NULL);
        if (cfd < 0) {
            if (errno == EINTR) continue;
            break;
        }
        handle_client(cfd);
        close(cfd);
    }

    if (g_listen_fd >= 0) close(g_listen_fd);
    close_db();
    return 0;
}
